window.BIBLE["1Timothy"] = {"1":{"chapter":"1","title":"PAUL'S GOSPEL CHARGE","verses":{"1":{"text":"Paul, an apostle of Jesus Christ by the commandment of God our Saviour, and Lord Jesus Christ, which is our hope;","ref":"1 Timothy 1:1","synthesized":"Paul, an apostle of Christ Jesus by the command of God our Savior and of Christ Jesus our hope,","sources":{"KJV":{"text":"Paul, an apostle of Jesus Christ by the commandment of God our Saviour, and Lord Jesus Christ, which is our hope;"},"BSB":{"text":"Paul, an apostle of Christ Jesus by the command of God our Savior and of Christ Jesus our hope,"}},"definableWords":["apostle","Christ","God","hope"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"Unto Timothy, my own son in the faith: Grace, mercy, and peace, from God our Father and Jesus Christ our Lord.","ref":"1 Timothy 1:2","synthesized":"To Timothy, my true child in the faith:  Grace, mercy, and peace from God the Father and Christ Jesus our Lord.","sources":{"KJV":{"text":"Unto Timothy, my own son in the faith: Grace, mercy, and peace, from God our Father and Jesus Christ our Lord."},"BSB":{"text":"To Timothy, my true child in the faith:  Grace, mercy, and peace from God the Father and Christ Jesus our Lord."}},"definableWords":["faith","grace","mercy","peace","God","Father","Christ","Lord"],"peopleInVerse":["Jesus"]},"3":{"text":"As I besought thee to abide still at Ephesus, when I went into Macedonia, that thou mightest charge some that they teach no other doctrine,","ref":"1 Timothy 1:3","synthesized":"As I urged you on my departure to Macedonia, you should stay on at Ephesus to instruct certain men not to teach false doctrines","sources":{"KJV":{"text":"As I besought thee to abide still at Ephesus, when I went into Macedonia, that thou mightest charge some that they teach no other doctrine,"},"BSB":{"text":"As I urged you on my departure to Macedonia, you should stay on at Ephesus to instruct certain men not to teach false doctrines"}},"definableWords":["men"],"peopleInVerse":[]},"4":{"text":"Neither give heed to fables and endless genealogies, which minister questions, rather than godly edifying which is in faith: so do.","ref":"1 Timothy 1:4","synthesized":"or devote themselves to myths and endless genealogies, which promote speculation rather than the stewardship of God’s work, which is by faith.","sources":{"KJV":{"text":"Neither give heed to fables and endless genealogies, which minister questions, rather than godly edifying which is in faith: so do."},"BSB":{"text":"or devote themselves to myths and endless genealogies, which promote speculation rather than the stewardship of God’s work, which is by faith."}},"definableWords":["or","God","work","faith"],"peopleInVerse":[]},"5":{"text":"Now the end of the commandment is charity out of a pure heart, and of a good conscience, and of faith unfeigned:","ref":"1 Timothy 1:5","synthesized":"The goal of our instruction is the love that comes from a pure heart, a clear conscience, and a sincere faith.","sources":{"KJV":{"text":"Now the end of the commandment is charity out of a pure heart, and of a good conscience, and of faith unfeigned:"},"BSB":{"text":"The goal of our instruction is the love that comes from a pure heart, a clear conscience, and a sincere faith."}},"definableWords":["love","heart","faith"],"peopleInVerse":[]},"6":{"text":"From which some having swerved have turned aside unto vain jangling;","ref":"1 Timothy 1:6","synthesized":"Some have strayed from these ways and turned aside to empty talk.","sources":{"KJV":{"text":"From which some having swerved have turned aside unto vain jangling;"},"BSB":{"text":"Some have strayed from these ways and turned aside to empty talk."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Desiring to be teachers of the law; understanding neither what they say, nor whereof they affirm.","ref":"1 Timothy 1:7","synthesized":"They want to be teachers of the law, but they do not understand what they are saying or that which they so confidently assert.","sources":{"KJV":{"text":"Desiring to be teachers of the law; understanding neither what they say, nor whereof they affirm."},"BSB":{"text":"They want to be teachers of the law, but they do not understand what they are saying or that which they so confidently assert."}},"definableWords":["law","or"],"peopleInVerse":[]},"8":{"text":"But we know that the law is good, if a man use it lawfully;","ref":"1 Timothy 1:8","synthesized":"Now we know that the law is good, if one uses it legitimately.","sources":{"KJV":{"text":"But we know that the law is good, if a man use it lawfully;"},"BSB":{"text":"Now we know that the law is good, if one uses it legitimately."}},"definableWords":["law","good","one"],"peopleInVerse":[]},"9":{"text":"Knowing this, that the law is not made for a righteous man, but for the lawless and disobedient, for the ungodly and for sinners, for unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,","ref":"1 Timothy 1:9","synthesized":"We realize that law is not enacted for the righteous, but for the lawless and rebellious, for the ungodly and sinful, for the unholy and profane, for killers of father or mother, for murderers,","sources":{"KJV":{"text":"Knowing this, that the law is not made for a righteous man, but for the lawless and disobedient, for the ungodly and for sinners, for unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,"},"BSB":{"text":"We realize that law is not enacted for the righteous, but for the lawless and rebellious, for the ungodly and sinful, for the unholy and profane, for killers of father or mother, for murderers,"}},"definableWords":["law","righteous","father","or","mother"],"peopleInVerse":[]},"10":{"text":"For whoremongers, for them that defile themselves with mankind, for menstealers, for liars, for perjured persons, and if there be any other thing that is contrary to sound doctrine;","ref":"1 Timothy 1:10","synthesized":"for the sexually immoral, for homosexuals, for slave traders and liars and perjurers, and for anyone else who is averse to sound teaching","sources":{"KJV":{"text":"For whoremongers, for them that defile themselves with mankind, for menstealers, for liars, for perjured persons, and if there be any other thing that is contrary to sound doctrine;"},"BSB":{"text":"for the sexually immoral, for homosexuals, for slave traders and liars and perjurers, and for anyone else who is averse to sound teaching"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"According to the glorious gospel of the blessed God, which was committed to my trust.","ref":"1 Timothy 1:11","synthesized":"that agrees with the glorious gospel of the blessed God, with which I have been entrusted.","sources":{"KJV":{"text":"According to the glorious gospel of the blessed God, which was committed to my trust."},"BSB":{"text":"that agrees with the glorious gospel of the blessed God, with which I have been entrusted."}},"definableWords":["gospel","blessed","God"],"peopleInVerse":[]},"12":{"text":"And I thank Christ Jesus our Lord, who hath enabled me, for that he counted me faithful, putting me into the ministry;","ref":"1 Timothy 1:12","synthesized":"I thank Christ Jesus our Lord, who has strengthened me, that He considered me faithful and appointed me to service.","sources":{"KJV":{"text":"And I thank Christ Jesus our Lord, who hath enabled me, for that he counted me faithful, putting me into the ministry;"},"BSB":{"text":"I thank Christ Jesus our Lord, who has strengthened me, that He considered me faithful and appointed me to service."}},"definableWords":["Christ","Lord"],"peopleInVerse":["Jesus"]},"13":{"text":"Who was before a blasphemer, and a persecutor, and injurious: but I obtained mercy, because I did it ignorantly in unbelief.","ref":"1 Timothy 1:13","synthesized":"I was formerly a blasphemer, a persecutor, and a violent man; yet because I had acted in ignorance and unbelief, I was shown mercy.","sources":{"KJV":{"text":"Who was before a blasphemer, and a persecutor, and injurious: but I obtained mercy, because I did it ignorantly in unbelief."},"BSB":{"text":"I was formerly a blasphemer, a persecutor, and a violent man; yet because I had acted in ignorance and unbelief, I was shown mercy."}},"definableWords":["man","mercy"],"peopleInVerse":[]},"14":{"text":"And the grace of our Lord was exceeding abundant with faith and love which is in Christ Jesus.","ref":"1 Timothy 1:14","synthesized":"And the grace of our Lord overflowed to me, along with the faith and love that are in Christ Jesus.","sources":{"KJV":{"text":"And the grace of our Lord was exceeding abundant with faith and love which is in Christ Jesus."},"BSB":{"text":"And the grace of our Lord overflowed to me, along with the faith and love that are in Christ Jesus."}},"definableWords":["grace","Lord","faith","love","Christ"],"peopleInVerse":["Jesus"]},"15":{"text":"This is a faithful saying, and worthy of all acceptation, that Christ Jesus came into the world to save sinners; of whom I am chief.","ref":"1 Timothy 1:15","synthesized":"This is a trustworthy saying, worthy of full acceptance: Christ Jesus came into the world to save sinners, of whom I am the worst.","sources":{"KJV":{"text":"This is a faithful saying, and worthy of all acceptation, that Christ Jesus came into the world to save sinners; of whom I am chief."},"BSB":{"text":"This is a trustworthy saying, worthy of full acceptance: Christ Jesus came into the world to save sinners, of whom I am the worst."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"16":{"text":"Howbeit for this cause I obtained mercy, that in me first Jesus Christ might shew forth all longsuffering, for a pattern to them which should hereafter believe on him to life everlasting.","ref":"1 Timothy 1:16","synthesized":"But for this very reason I was shown mercy, so that in me, the worst of sinners, Christ Jesus might display His perfect patience as an example to those who would believe in Him for eternal life.","sources":{"KJV":{"text":"Howbeit for this cause I obtained mercy, that in me first Jesus Christ might shew forth all longsuffering, for a pattern to them which should hereafter believe on him to life everlasting."},"BSB":{"text":"But for this very reason I was shown mercy, so that in me, the worst of sinners, Christ Jesus might display His perfect patience as an example to those who would believe in Him for eternal life."}},"definableWords":["mercy","Christ","patience","eternal","life"],"peopleInVerse":["Jesus"]},"17":{"text":"Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever. Amen.","ref":"1 Timothy 1:17","synthesized":"Now to the King eternal, immortal, and invisible, the only God, be honor and glory forever and ever. Amen.","sources":{"KJV":{"text":"Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever. Amen."},"BSB":{"text":"Now to the King eternal, immortal, and invisible, the only God, be honor and glory forever and ever. Amen."}},"definableWords":["King","eternal","God","glory"],"peopleInVerse":[]},"18":{"text":"This charge I commit unto thee, son Timothy, according to the prophecies which went before on thee, that thou by them mightest war a good warfare;","ref":"1 Timothy 1:18","synthesized":"Timothy, my child, I entrust you with this command in keeping with the previous prophecies about you, so that by them you may fight the good fight,","sources":{"KJV":{"text":"This charge I commit unto thee, son Timothy, according to the prophecies which went before on thee, that thou by them mightest war a good warfare;"},"BSB":{"text":"Timothy, my child, I entrust you with this command in keeping with the previous prophecies about you, so that by them you may fight the good fight,"}},"definableWords":["fight","good"],"peopleInVerse":[]},"19":{"text":"Holding faith, and a good conscience; which some having put away concerning faith have made shipwreck:","ref":"1 Timothy 1:19","synthesized":"holding on to faith and a good conscience, which some have rejected and thereby shipwrecked their faith.","sources":{"KJV":{"text":"Holding faith, and a good conscience; which some having put away concerning faith have made shipwreck:"},"BSB":{"text":"holding on to faith and a good conscience, which some have rejected and thereby shipwrecked their faith."}},"definableWords":["faith","good"],"peopleInVerse":[]},"20":{"text":"Of whom is Hymenaeus and Alexander; whom I have delivered unto Satan, that they may learn not to blaspheme.","ref":"1 Timothy 1:20","synthesized":"Among them are Hymenaeus and Alexander, whom I have handed over to Satan to be taught not to blaspheme.","sources":{"KJV":{"text":"Of whom is Hymenaeus and Alexander; whom I have delivered unto Satan, that they may learn not to blaspheme."},"BSB":{"text":"Among them are Hymenaeus and Alexander, whom I have handed over to Satan to be taught not to blaspheme."}},"definableWords":["Satan"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"ONE MEDIATOR BETWEEN GOD AND MEN","verses":{"1":{"text":"I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men;","ref":"1 Timothy 2:1","synthesized":"First of all, then, I urge that petitions, prayers, intercessions, and thanksgiving be offered for everyone—","sources":{"KJV":{"text":"I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men;"},"BSB":{"text":"First of all, then, I urge that petitions, prayers, intercessions, and thanksgiving be offered for everyone—"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"For kings, and for all that are in authority; that we may lead a quiet and peaceable life in all godliness and honesty.","ref":"1 Timothy 2:2","synthesized":"for kings and all those in authority—so that we may lead tranquil and quiet lives in all godliness and dignity.","sources":{"KJV":{"text":"For kings, and for all that are in authority; that we may lead a quiet and peaceable life in all godliness and honesty."},"BSB":{"text":"for kings and all those in authority—so that we may lead tranquil and quiet lives in all godliness and dignity."}},"definableWords":["kings"],"peopleInVerse":[]},"3":{"text":"For this is good and acceptable in the sight of God our Saviour;","ref":"1 Timothy 2:3","synthesized":"This is good and pleasing in the sight of God our Savior,","sources":{"KJV":{"text":"For this is good and acceptable in the sight of God our Saviour;"},"BSB":{"text":"This is good and pleasing in the sight of God our Savior,"}},"definableWords":["good","God"],"peopleInVerse":[]},"4":{"text":"Who will have all men to be saved, and to come unto the knowledge of the truth.","ref":"1 Timothy 2:4","synthesized":"who wants everyone to be saved and to come to the knowledge of the truth.","sources":{"KJV":{"text":"Who will have all men to be saved, and to come unto the knowledge of the truth."},"BSB":{"text":"who wants everyone to be saved and to come to the knowledge of the truth."}},"definableWords":["knowledge","truth"],"peopleInVerse":[]},"5":{"text":"For there is one God, and one mediator between God and men, the man Christ Jesus;","ref":"1 Timothy 2:5","synthesized":"For there is one God, and there is one mediator between God and men, the man Christ Jesus,","sources":{"KJV":{"text":"For there is one God, and one mediator between God and men, the man Christ Jesus;"},"BSB":{"text":"For there is one God, and there is one mediator between God and men, the man Christ Jesus,"}},"definableWords":["one","God","men","man","Christ"],"peopleInVerse":["Jesus"]},"6":{"text":"Who gave himself a ransom for all, to be testified in due time.","ref":"1 Timothy 2:6","synthesized":"who gave Himself as a ransom for all—the testimony that was given at just the right time.","sources":{"KJV":{"text":"Who gave himself a ransom for all, to be testified in due time."},"BSB":{"text":"who gave Himself as a ransom for all—the testimony that was given at just the right time."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Whereunto I am ordained a preacher, and an apostle, (I speak the truth in Christ, and lie not;) a teacher of the Gentiles in faith and verity.","ref":"1 Timothy 2:7","synthesized":"For this reason I was appointed as a preacher, an apostle, and a faithful and true teacher of the Gentiles. I am telling the truth; I am not lying about anything.","sources":{"KJV":{"text":"Whereunto I am ordained a preacher, and an apostle, (I speak the truth in Christ, and lie not;) a teacher of the Gentiles in faith and verity."},"BSB":{"text":"For this reason I was appointed as a preacher, an apostle, and a faithful and true teacher of the Gentiles. I am telling the truth; I am not lying about anything."}},"definableWords":["apostle","truth"],"peopleInVerse":[]},"8":{"text":"I will therefore that men pray every where, lifting up holy hands, without wrath and doubting.","ref":"1 Timothy 2:8","synthesized":"Therefore I want the men everywhere to pray, lifting up holy hands, without anger or dissension.","sources":{"KJV":{"text":"I will therefore that men pray every where, lifting up holy hands, without wrath and doubting."},"BSB":{"text":"Therefore I want the men everywhere to pray, lifting up holy hands, without anger or dissension."}},"definableWords":["men","holy","anger","or"],"peopleInVerse":[]},"9":{"text":"In like manner also, that women adorn themselves in modest apparel, with shamefacedness and sobriety; not with broided hair, or gold, or pearls, or costly array;","ref":"1 Timothy 2:9","synthesized":"Likewise, I want the women to adorn themselves with respectable apparel, with modesty, and with self-control, not with braided hair or gold or pearls or expensive clothes,","sources":{"KJV":{"text":"In like manner also, that women adorn themselves in modest apparel, with shamefacedness and sobriety; not with broided hair, or gold, or pearls, or costly array;"},"BSB":{"text":"Likewise, I want the women to adorn themselves with respectable apparel, with modesty, and with self-control, not with braided hair or gold or pearls or expensive clothes,"}},"definableWords":["women","or"],"peopleInVerse":[]},"10":{"text":"But (which becometh women professing godliness) with good works.","ref":"1 Timothy 2:10","synthesized":"but with good deeds, as is proper for women who profess to worship God.","sources":{"KJV":{"text":"But (which becometh women professing godliness) with good works."},"BSB":{"text":"but with good deeds, as is proper for women who profess to worship God."}},"definableWords":["good","women","worship","God"],"peopleInVerse":[]},"11":{"text":"Let the woman learn in silence with all subjection.","ref":"1 Timothy 2:11","synthesized":"A woman must learn in quietness and full submissiveness.","sources":{"KJV":{"text":"Let the woman learn in silence with all subjection."},"BSB":{"text":"A woman must learn in quietness and full submissiveness."}},"definableWords":["woman"],"peopleInVerse":[]},"12":{"text":"But I suffer not a woman to teach, nor to usurp authority over the man, but to be in silence.","ref":"1 Timothy 2:12","synthesized":"I do not permit a woman to teach or to exercise authority over a man; she is to remain quiet.","sources":{"KJV":{"text":"But I suffer not a woman to teach, nor to usurp authority over the man, but to be in silence."},"BSB":{"text":"I do not permit a woman to teach or to exercise authority over a man; she is to remain quiet."}},"definableWords":["woman","or","man"],"peopleInVerse":[]},"13":{"text":"For Adam was first formed, then Eve.","ref":"1 Timothy 2:13","synthesized":"For Adam was formed first, and then Eve.","sources":{"KJV":{"text":"For Adam was first formed, then Eve."},"BSB":{"text":"For Adam was formed first, and then Eve."}},"definableWords":["Adam","formed","Eve"],"peopleInVerse":["Adam","Eve"]},"14":{"text":"And Adam was not deceived, but the woman being deceived was in the transgression.","ref":"1 Timothy 2:14","synthesized":"And it was not Adam who was deceived, but the woman who was deceived and fell into transgression.","sources":{"KJV":{"text":"And Adam was not deceived, but the woman being deceived was in the transgression."},"BSB":{"text":"And it was not Adam who was deceived, but the woman who was deceived and fell into transgression."}},"definableWords":["Adam","woman","transgression"],"peopleInVerse":["Adam"]},"15":{"text":"Notwithstanding she shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety.","ref":"1 Timothy 2:15","synthesized":"Women, however, will be saved through childbearing, if they continue in faith, love, and holiness, with self-control.","sources":{"KJV":{"text":"Notwithstanding she shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety."},"BSB":{"text":"Women, however, will be saved through childbearing, if they continue in faith, love, and holiness, with self-control."}},"definableWords":["women","faith","love"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"QUALIFICATIONS FOR LEADERS","verses":{"1":{"text":"This is a true saying, If a man desire the office of a bishop, he desireth a good work.","ref":"1 Timothy 3:1","synthesized":"This is a trustworthy saying: If anyone aspires to be an overseer, he desires a noble task.","sources":{"KJV":{"text":"This is a true saying, If a man desire the office of a bishop, he desireth a good work."},"BSB":{"text":"This is a trustworthy saying: If anyone aspires to be an overseer, he desires a noble task."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"A bishop then must be blameless, the husband of one wife, vigilant, sober, of good behaviour, given to hospitality, apt to teach;","ref":"1 Timothy 3:2","synthesized":"An overseer, then, must be above reproach, the husband of but one wife, temperate, self-controlled, respectable, hospitable, able to teach,","sources":{"KJV":{"text":"A bishop then must be blameless, the husband of one wife, vigilant, sober, of good behaviour, given to hospitality, apt to teach;"},"BSB":{"text":"An overseer, then, must be above reproach, the husband of but one wife, temperate, self-controlled, respectable, hospitable, able to teach,"}},"definableWords":["husband","one","wife"],"peopleInVerse":[]},"3":{"text":"Not given to wine, no striker, not greedy of filthy lucre; but patient, not a brawler, not covetous;","ref":"1 Timothy 3:3","synthesized":"not dependent on wine, not violent but gentle, peaceable, and free of the love of money.","sources":{"KJV":{"text":"Not given to wine, no striker, not greedy of filthy lucre; but patient, not a brawler, not covetous;"},"BSB":{"text":"not dependent on wine, not violent but gentle, peaceable, and free of the love of money."}},"definableWords":["love"],"peopleInVerse":[]},"4":{"text":"One that ruleth well his own house, having his children in subjection with all gravity;","ref":"1 Timothy 3:4","synthesized":"An overseer must manage his own household well and keep his children under control, with complete dignity.","sources":{"KJV":{"text":"One that ruleth well his own house, having his children in subjection with all gravity;"},"BSB":{"text":"An overseer must manage his own household well and keep his children under control, with complete dignity."}},"definableWords":["keep"],"peopleInVerse":[]},"5":{"text":"(For if a man know not how to rule his own house, how shall he take care of the church of God?)","ref":"1 Timothy 3:5","synthesized":"For if someone does not know how to manage his own household, how can he care for the church of God?","sources":{"KJV":{"text":"(For if a man know not how to rule his own house, how shall he take care of the church of God?)"},"BSB":{"text":"For if someone does not know how to manage his own household, how can he care for the church of God?"}},"definableWords":["church","God"],"peopleInVerse":[]},"6":{"text":"Not a novice, lest being lifted up with pride he fall into the condemnation of the devil.","ref":"1 Timothy 3:6","synthesized":"He must not be a recent convert, or he may become conceited and fall under the same condemnation as the devil.","sources":{"KJV":{"text":"Not a novice, lest being lifted up with pride he fall into the condemnation of the devil."},"BSB":{"text":"He must not be a recent convert, or he may become conceited and fall under the same condemnation as the devil."}},"definableWords":["or","devil"],"peopleInVerse":[]},"7":{"text":"Moreover he must have a good report of them which are without; lest he fall into reproach and the snare of the devil.","ref":"1 Timothy 3:7","synthesized":"Furthermore, he must have a good reputation with outsiders, so that he will not fall into disgrace and into the snare of the devil.","sources":{"KJV":{"text":"Moreover he must have a good report of them which are without; lest he fall into reproach and the snare of the devil."},"BSB":{"text":"Furthermore, he must have a good reputation with outsiders, so that he will not fall into disgrace and into the snare of the devil."}},"definableWords":["good","devil"],"peopleInVerse":[]},"8":{"text":"Likewise must the deacons be grave, not doubletongued, not given to much wine, not greedy of filthy lucre;","ref":"1 Timothy 3:8","synthesized":"Deacons likewise must be dignified, not double-tongued or given to much wine or greedy for money.","sources":{"KJV":{"text":"Likewise must the deacons be grave, not doubletongued, not given to much wine, not greedy of filthy lucre;"},"BSB":{"text":"Deacons likewise must be dignified, not double-tongued or given to much wine or greedy for money."}},"definableWords":["or"],"peopleInVerse":[]},"9":{"text":"Holding the mystery of the faith in a pure conscience.","ref":"1 Timothy 3:9","synthesized":"They must hold to the mystery of the faith with a clear conscience.","sources":{"KJV":{"text":"Holding the mystery of the faith in a pure conscience."},"BSB":{"text":"They must hold to the mystery of the faith with a clear conscience."}},"definableWords":["faith"],"peopleInVerse":[]},"10":{"text":"And let these also first be proved; then let them use the office of a deacon, being found blameless.","ref":"1 Timothy 3:10","synthesized":"Additionally, they must first be tested. Then, if they are above reproach, let them serve as deacons.","sources":{"KJV":{"text":"And let these also first be proved; then let them use the office of a deacon, being found blameless."},"BSB":{"text":"Additionally, they must first be tested. Then, if they are above reproach, let them serve as deacons."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Even so must their wives be grave, not slanderers, sober, faithful in all things.","ref":"1 Timothy 3:11","synthesized":"In the same way, the women must be dignified, not slanderers, but temperate and faithful in all things.","sources":{"KJV":{"text":"Even so must their wives be grave, not slanderers, sober, faithful in all things."},"BSB":{"text":"In the same way, the women must be dignified, not slanderers, but temperate and faithful in all things."}},"definableWords":["way","women"],"peopleInVerse":[]},"12":{"text":"Let the deacons be the husbands of one wife, ruling their children and their own houses well.","ref":"1 Timothy 3:12","synthesized":"A deacon must be the husband of but one wife, a good manager of his children and of his own household.","sources":{"KJV":{"text":"Let the deacons be the husbands of one wife, ruling their children and their own houses well."},"BSB":{"text":"A deacon must be the husband of but one wife, a good manager of his children and of his own household."}},"definableWords":["deacon","husband","one","wife","good"],"peopleInVerse":[]},"13":{"text":"For they that have used the office of a deacon well purchase to themselves a good degree, and great boldness in the faith which is in Christ Jesus.","ref":"1 Timothy 3:13","synthesized":"For those who have served well as deacons acquire for themselves a high standing and great confidence in the faith that is in Christ Jesus.","sources":{"KJV":{"text":"For they that have used the office of a deacon well purchase to themselves a good degree, and great boldness in the faith which is in Christ Jesus."},"BSB":{"text":"For those who have served well as deacons acquire for themselves a high standing and great confidence in the faith that is in Christ Jesus."}},"definableWords":["great","faith","Christ"],"peopleInVerse":["Jesus"]},"14":{"text":"These things write I unto thee, hoping to come unto thee shortly:","ref":"1 Timothy 3:14","synthesized":"Although I hope to come to you soon, I am writing you these things","sources":{"KJV":{"text":"These things write I unto thee, hoping to come unto thee shortly:"},"BSB":{"text":"Although I hope to come to you soon, I am writing you these things"}},"definableWords":["hope"],"peopleInVerse":[]},"15":{"text":"But if I tarry long, that thou mayest know how thou oughtest to behave thyself in the house of God, which is the church of the living God, the pillar and ground of the truth.","ref":"1 Timothy 3:15","synthesized":"in case I am delayed, so that you will know how each one must conduct himself in God’s household, which is the church of the living God, the pillar and foundation of the truth.","sources":{"KJV":{"text":"But if I tarry long, that thou mayest know how thou oughtest to behave thyself in the house of God, which is the church of the living God, the pillar and ground of the truth."},"BSB":{"text":"in case I am delayed, so that you will know how each one must conduct himself in God’s household, which is the church of the living God, the pillar and foundation of the truth."}},"definableWords":["one","God","church","living","truth"],"peopleInVerse":[]},"16":{"text":"And without controversy great is the mystery of godliness: God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory.","ref":"1 Timothy 3:16","synthesized":"By common confession, the mystery of godliness is great:  He appeared in the flesh, was vindicated by the Spirit, was seen by angels, was proclaimed among the nations, was believed in throughout the world, was taken up in glory.","sources":{"KJV":{"text":"And without controversy great is the mystery of godliness: God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory."},"BSB":{"text":"By common confession, the mystery of godliness is great:  He appeared in the flesh, was vindicated by the Spirit, was seen by angels, was proclaimed among the nations, was believed in throughout the world, was taken up in glory."}},"definableWords":["great","flesh","Spirit","nations","believed","glory"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"DOCTRINES OF DEVILS","verses":{"1":{"text":"Now the Spirit speaketh expressly, that in the latter times some shall depart from the faith, giving heed to seducing spirits, and doctrines of devils;","ref":"1 Timothy 4:1","synthesized":"Now the Spirit expressly states that in later times some will abandon the faith to follow deceitful spirits and the teachings of demons,","sources":{"KJV":{"text":"Now the Spirit speaketh expressly, that in the latter times some shall depart from the faith, giving heed to seducing spirits, and doctrines of devils;"},"BSB":{"text":"Now the Spirit expressly states that in later times some will abandon the faith to follow deceitful spirits and the teachings of demons,"}},"definableWords":["Spirit","faith"],"peopleInVerse":[]},"2":{"text":"Speaking lies in hypocrisy; having their conscience seared with a hot iron;","ref":"1 Timothy 4:2","synthesized":"influenced by the hypocrisy of liars, whose consciences are seared with a hot iron.","sources":{"KJV":{"text":"Speaking lies in hypocrisy; having their conscience seared with a hot iron;"},"BSB":{"text":"influenced by the hypocrisy of liars, whose consciences are seared with a hot iron."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Forbidding to marry, and commanding to abstain from meats, which God hath created to be received with thanksgiving of them which believe and know the truth.","ref":"1 Timothy 4:3","synthesized":"They will prohibit marriage and require abstinence from certain foods that God has created to be received with thanksgiving by those who believe and know the truth.","sources":{"KJV":{"text":"Forbidding to marry, and commanding to abstain from meats, which God hath created to be received with thanksgiving of them which believe and know the truth."},"BSB":{"text":"They will prohibit marriage and require abstinence from certain foods that God has created to be received with thanksgiving by those who believe and know the truth."}},"definableWords":["God","created","truth"],"peopleInVerse":[]},"4":{"text":"For every creature of God is good, and nothing to be refused, if it be received with thanksgiving:","ref":"1 Timothy 4:4","synthesized":"For every creation of God is good, and nothing that is received with thanksgiving should be rejected,","sources":{"KJV":{"text":"For every creature of God is good, and nothing to be refused, if it be received with thanksgiving:"},"BSB":{"text":"For every creation of God is good, and nothing that is received with thanksgiving should be rejected,"}},"definableWords":["God","good"],"peopleInVerse":[]},"5":{"text":"For it is sanctified by the word of God and prayer.","ref":"1 Timothy 4:5","synthesized":"because it is sanctified by the word of God and prayer.","sources":{"KJV":{"text":"For it is sanctified by the word of God and prayer."},"BSB":{"text":"because it is sanctified by the word of God and prayer."}},"definableWords":["word","God","prayer"],"peopleInVerse":[]},"6":{"text":"If thou put the brethren in remembrance of these things, thou shalt be a good minister of Jesus Christ, nourished up in the words of faith and of good doctrine, whereunto thou hast attained.","ref":"1 Timothy 4:6","synthesized":"By pointing out these things to the brothers, you will be a good servant of Christ Jesus, nourished by the words of faith and sound instruction that you have followed.","sources":{"KJV":{"text":"If thou put the brethren in remembrance of these things, thou shalt be a good minister of Jesus Christ, nourished up in the words of faith and of good doctrine, whereunto thou hast attained."},"BSB":{"text":"By pointing out these things to the brothers, you will be a good servant of Christ Jesus, nourished by the words of faith and sound instruction that you have followed."}},"definableWords":["good","servant","Christ","faith"],"peopleInVerse":["Jesus"]},"7":{"text":"But refuse profane and old wives’ fables, and exercise thyself rather unto godliness.","ref":"1 Timothy 4:7","synthesized":"But reject irreverent, silly myths. Instead, train yourself for godliness.","sources":{"KJV":{"text":"But refuse profane and old wives’ fables, and exercise thyself rather unto godliness."},"BSB":{"text":"But reject irreverent, silly myths. Instead, train yourself for godliness."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For bodily exercise profiteth little: but godliness is profitable unto all things, having promise of the life that now is, and of that which is to come.","ref":"1 Timothy 4:8","synthesized":"For physical exercise is of limited value, but godliness is valuable in every way, holding promise for the present life and for the one to come.","sources":{"KJV":{"text":"For bodily exercise profiteth little: but godliness is profitable unto all things, having promise of the life that now is, and of that which is to come."},"BSB":{"text":"For physical exercise is of limited value, but godliness is valuable in every way, holding promise for the present life and for the one to come."}},"definableWords":["way","promise","life","one"],"peopleInVerse":[]},"9":{"text":"This is a faithful saying and worthy of all acceptation.","ref":"1 Timothy 4:9","synthesized":"This is a trustworthy saying, worthy of full acceptance.","sources":{"KJV":{"text":"This is a faithful saying and worthy of all acceptation."},"BSB":{"text":"This is a trustworthy saying, worthy of full acceptance."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For therefore we both labour and suffer reproach, because we trust in the living God, who is the Saviour of all men, specially of those that believe.","ref":"1 Timothy 4:10","synthesized":"To this end we labor and strive, because we have set our hope on the living God, who is the Savior of everyone, and especially of those who believe.","sources":{"KJV":{"text":"For therefore we both labour and suffer reproach, because we trust in the living God, who is the Saviour of all men, specially of those that believe."},"BSB":{"text":"To this end we labor and strive, because we have set our hope on the living God, who is the Savior of everyone, and especially of those who believe."}},"definableWords":["hope","living","God"],"peopleInVerse":[]},"11":{"text":"These things command and teach.","ref":"1 Timothy 4:11","synthesized":"Command and teach these things.","sources":{"KJV":{"text":"These things command and teach."},"BSB":{"text":"Command and teach these things."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Let no man despise thy youth; but be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity.","ref":"1 Timothy 4:12","synthesized":"Let no one despise your youth, but set an example for the believers in speech, in conduct, in love, in faith, in purity.","sources":{"KJV":{"text":"Let no man despise thy youth; but be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity."},"BSB":{"text":"Let no one despise your youth, but set an example for the believers in speech, in conduct, in love, in faith, in purity."}},"definableWords":["one","love","faith"],"peopleInVerse":[]},"13":{"text":"Till I come, give attendance to reading, to exhortation, to doctrine.","ref":"1 Timothy 4:13","synthesized":"Until I come, devote yourself to the public reading of Scripture, to exhortation, and to teaching.","sources":{"KJV":{"text":"Till I come, give attendance to reading, to exhortation, to doctrine."},"BSB":{"text":"Until I come, devote yourself to the public reading of Scripture, to exhortation, and to teaching."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Neglect not the gift that is in thee, which was given thee by prophecy, with the laying on of the hands of the presbytery.","ref":"1 Timothy 4:14","synthesized":"Do not neglect the gift that is in you, which was given you through the prophecy spoken over you at the laying on of the hands of the elders.","sources":{"KJV":{"text":"Neglect not the gift that is in thee, which was given thee by prophecy, with the laying on of the hands of the presbytery."},"BSB":{"text":"Do not neglect the gift that is in you, which was given you through the prophecy spoken over you at the laying on of the hands of the elders."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Meditate upon these things; give thyself wholly to them; that thy profiting may appear to all.","ref":"1 Timothy 4:15","synthesized":"Be diligent in these matters and absorbed in them, so that your progress will be evident to all.","sources":{"KJV":{"text":"Meditate upon these things; give thyself wholly to them; that thy profiting may appear to all."},"BSB":{"text":"Be diligent in these matters and absorbed in them, so that your progress will be evident to all."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Take heed unto thyself, and unto the doctrine; continue in them: for in doing this thou shalt both save thyself, and them that hear thee.","ref":"1 Timothy 4:16","synthesized":"Pay close attention to your life and to your teaching. Persevere in these things, for by so doing you will save both yourself and those who hear you.","sources":{"KJV":{"text":"Take heed unto thyself, and unto the doctrine; continue in them: for in doing this thou shalt both save thyself, and them that hear thee."},"BSB":{"text":"Pay close attention to your life and to your teaching. Persevere in these things, for by so doing you will save both yourself and those who hear you."}},"definableWords":["life","hear"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"INSTRUCTIONS ABOUT WIDOWS AND ELDERS","verses":{"1":{"text":"Rebuke not an elder, but intreat him as a father; and the younger men as brethren;","ref":"1 Timothy 5:1","synthesized":"Do not rebuke an older man, but appeal to him as to a father.  Treat younger men as brothers,","sources":{"KJV":{"text":"Rebuke not an elder, but intreat him as a father; and the younger men as brethren;"},"BSB":{"text":"Do not rebuke an older man, but appeal to him as to a father.  Treat younger men as brothers,"}},"definableWords":["man","father","men"],"peopleInVerse":[]},"2":{"text":"The elder women as mothers; the younger as sisters, with all purity.","ref":"1 Timothy 5:2","synthesized":"older women as mothers, and younger women as sisters, with absolute purity.","sources":{"KJV":{"text":"The elder women as mothers; the younger as sisters, with all purity."},"BSB":{"text":"older women as mothers, and younger women as sisters, with absolute purity."}},"definableWords":["women"],"peopleInVerse":[]},"3":{"text":"Honour widows that are widows indeed.","ref":"1 Timothy 5:3","synthesized":"Honor the widows who are truly widows.","sources":{"KJV":{"text":"Honour widows that are widows indeed."},"BSB":{"text":"Honor the widows who are truly widows."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But if any widow have children or nephews, let them learn first to shew piety at home, and to requite their parents: for that is good and acceptable before God.","ref":"1 Timothy 5:4","synthesized":"But if a widow has children or grandchildren, they must first learn to show godliness to their own family and repay their parents, for this is pleasing in the sight of God.","sources":{"KJV":{"text":"But if any widow have children or nephews, let them learn first to shew piety at home, and to requite their parents: for that is good and acceptable before God."},"BSB":{"text":"But if a widow has children or grandchildren, they must first learn to show godliness to their own family and repay their parents, for this is pleasing in the sight of God."}},"definableWords":["widow","or","family","God"],"peopleInVerse":[]},"5":{"text":"Now she that is a widow indeed, and desolate, trusteth in God, and continueth in supplications and prayers night and day.","ref":"1 Timothy 5:5","synthesized":"The widow who is truly in need and left all alone puts her hope in God and continues night and day in her petitions and prayers.","sources":{"KJV":{"text":"Now she that is a widow indeed, and desolate, trusteth in God, and continueth in supplications and prayers night and day."},"BSB":{"text":"The widow who is truly in need and left all alone puts her hope in God and continues night and day in her petitions and prayers."}},"definableWords":["widow","hope","God","night","day"],"peopleInVerse":[]},"6":{"text":"But she that liveth in pleasure is dead while she liveth.","ref":"1 Timothy 5:6","synthesized":"But she who lives for pleasure is dead even while she is still alive.","sources":{"KJV":{"text":"But she that liveth in pleasure is dead while she liveth."},"BSB":{"text":"But she who lives for pleasure is dead even while she is still alive."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And these things give in charge, that they may be blameless.","ref":"1 Timothy 5:7","synthesized":"Give these instructions to the believers, so that they will be above reproach.","sources":{"KJV":{"text":"And these things give in charge, that they may be blameless."},"BSB":{"text":"Give these instructions to the believers, so that they will be above reproach."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But if any provide not for his own, and specially for those of his own house, he hath denied the faith, and is worse than an infidel.","ref":"1 Timothy 5:8","synthesized":"If anyone does not provide for his own, and especially his own household, he has denied the faith and is worse than an unbeliever.","sources":{"KJV":{"text":"But if any provide not for his own, and specially for those of his own house, he hath denied the faith, and is worse than an infidel."},"BSB":{"text":"If anyone does not provide for his own, and especially his own household, he has denied the faith and is worse than an unbeliever."}},"definableWords":["faith"],"peopleInVerse":[]},"9":{"text":"Let not a widow be taken into the number under threescore years old, having been the wife of one man,","ref":"1 Timothy 5:9","synthesized":"A widow should be enrolled if she is at least sixty years old, the wife of one man,","sources":{"KJV":{"text":"Let not a widow be taken into the number under threescore years old, having been the wife of one man,"},"BSB":{"text":"A widow should be enrolled if she is at least sixty years old, the wife of one man,"}},"definableWords":["widow","years","wife","one","man"],"peopleInVerse":[]},"10":{"text":"Well reported of for good works; if she have brought up children, if she have lodged strangers, if she have washed the saints’ feet, if she have relieved the afflicted, if she have diligently followed every good work.","ref":"1 Timothy 5:10","synthesized":"and well known for good deeds such as bringing up children, entertaining strangers, washing the feet of the saints, imparting relief to the afflicted, and devoting herself to every good work.","sources":{"KJV":{"text":"Well reported of for good works; if she have brought up children, if she have lodged strangers, if she have washed the saints’ feet, if she have relieved the afflicted, if she have diligently followed every good work."},"BSB":{"text":"and well known for good deeds such as bringing up children, entertaining strangers, washing the feet of the saints, imparting relief to the afflicted, and devoting herself to every good work."}},"definableWords":["good","work"],"peopleInVerse":[]},"11":{"text":"But the younger widows refuse: for when they have begun to wax wanton against Christ, they will marry;","ref":"1 Timothy 5:11","synthesized":"But refuse to enroll younger widows. For when their passions draw them away from Christ, they will want to marry,","sources":{"KJV":{"text":"But the younger widows refuse: for when they have begun to wax wanton against Christ, they will marry;"},"BSB":{"text":"But refuse to enroll younger widows. For when their passions draw them away from Christ, they will want to marry,"}},"definableWords":["Christ"],"peopleInVerse":[]},"12":{"text":"Having damnation, because they have cast off their first faith.","ref":"1 Timothy 5:12","synthesized":"and thus will incur judgment because they are setting aside their first faith.","sources":{"KJV":{"text":"Having damnation, because they have cast off their first faith."},"BSB":{"text":"and thus will incur judgment because they are setting aside their first faith."}},"definableWords":["judgment","faith"],"peopleInVerse":[]},"13":{"text":"And withal they learn to be idle, wandering about from house to house; and not only idle, but tattlers also and busybodies, speaking things which they ought not.","ref":"1 Timothy 5:13","synthesized":"At the same time they will also learn to be idle, going from house to house and being not only idle, but also gossips and busybodies, discussing things they should not mention.","sources":{"KJV":{"text":"And withal they learn to be idle, wandering about from house to house; and not only idle, but tattlers also and busybodies, speaking things which they ought not."},"BSB":{"text":"At the same time they will also learn to be idle, going from house to house and being not only idle, but also gossips and busybodies, discussing things they should not mention."}},"definableWords":["house"],"peopleInVerse":[]},"14":{"text":"I will therefore that the younger women marry, bear children, guide the house, give none occasion to the adversary to speak reproachfully.","ref":"1 Timothy 5:14","synthesized":"So I advise the younger widows to marry, have children, and manage their households, denying the adversary occasion for slander.","sources":{"KJV":{"text":"I will therefore that the younger women marry, bear children, guide the house, give none occasion to the adversary to speak reproachfully."},"BSB":{"text":"So I advise the younger widows to marry, have children, and manage their households, denying the adversary occasion for slander."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"For some are already turned aside after Satan.","ref":"1 Timothy 5:15","synthesized":"For some have already turned aside to follow Satan.","sources":{"KJV":{"text":"For some are already turned aside after Satan."},"BSB":{"text":"For some have already turned aside to follow Satan."}},"definableWords":["Satan"],"peopleInVerse":[]},"16":{"text":"If any man or woman that believeth have widows, let them relieve them, and let not the church be charged; that it may relieve them that are widows indeed.","ref":"1 Timothy 5:16","synthesized":"If any believing woman has dependent widows, she must assist them and not allow the church to be burdened, so that it can help the widows who are truly in need.","sources":{"KJV":{"text":"If any man or woman that believeth have widows, let them relieve them, and let not the church be charged; that it may relieve them that are widows indeed."},"BSB":{"text":"If any believing woman has dependent widows, she must assist them and not allow the church to be burdened, so that it can help the widows who are truly in need."}},"definableWords":["woman","church"],"peopleInVerse":[]},"17":{"text":"Let the elders that rule well be counted worthy of double honour, especially they who labour in the word and doctrine.","ref":"1 Timothy 5:17","synthesized":"Elders who lead effectively are worthy of double honor, especially those who work hard at preaching and teaching.","sources":{"KJV":{"text":"Let the elders that rule well be counted worthy of double honour, especially they who labour in the word and doctrine."},"BSB":{"text":"Elders who lead effectively are worthy of double honor, especially those who work hard at preaching and teaching."}},"definableWords":["work"],"peopleInVerse":[]},"18":{"text":"For the scripture saith, Thou shalt not muzzle the ox that treadeth out the corn. And, The labourer is worthy of his reward.","ref":"1 Timothy 5:18","synthesized":"For the Scripture says, “Do not muzzle an ox while it is treading out the grain,” and, “The worker is worthy of his wages.”","sources":{"KJV":{"text":"For the scripture saith, Thou shalt not muzzle the ox that treadeth out the corn. And, The labourer is worthy of his reward."},"BSB":{"text":"For the Scripture says, “Do not muzzle an ox while it is treading out the grain,” and, “The worker is worthy of his wages.”"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Against an elder receive not an accusation, but before two or three witnesses.","ref":"1 Timothy 5:19","synthesized":"Do not entertain an accusation against an elder, except on the testimony of two or three witnesses.","sources":{"KJV":{"text":"Against an elder receive not an accusation, but before two or three witnesses."},"BSB":{"text":"Do not entertain an accusation against an elder, except on the testimony of two or three witnesses."}},"definableWords":["elder","or"],"peopleInVerse":[]},"20":{"text":"Them that sin rebuke before all, that others also may fear.","ref":"1 Timothy 5:20","synthesized":"But those who persist in sin should be rebuked in front of everyone, so that the others will stand in fear of sin.","sources":{"KJV":{"text":"Them that sin rebuke before all, that others also may fear."},"BSB":{"text":"But those who persist in sin should be rebuked in front of everyone, so that the others will stand in fear of sin."}},"definableWords":["sin","stand","fear"],"peopleInVerse":[]},"21":{"text":"I charge thee before God, and the Lord Jesus Christ, and the elect angels, that thou observe these things without preferring one before another, doing nothing by partiality.","ref":"1 Timothy 5:21","synthesized":"I solemnly charge you before God and Christ Jesus and the elect angels to maintain these principles without bias, and to do nothing out of partiality.","sources":{"KJV":{"text":"I charge thee before God, and the Lord Jesus Christ, and the elect angels, that thou observe these things without preferring one before another, doing nothing by partiality."},"BSB":{"text":"I solemnly charge you before God and Christ Jesus and the elect angels to maintain these principles without bias, and to do nothing out of partiality."}},"definableWords":["charge","God","Christ"],"peopleInVerse":["Jesus"]},"22":{"text":"Lay hands suddenly on no man, neither be partaker of other men’s sins: keep thyself pure.","ref":"1 Timothy 5:22","synthesized":"Do not be too quick in the laying on of hands and thereby share in the sins of others. Keep yourself pure.","sources":{"KJV":{"text":"Lay hands suddenly on no man, neither be partaker of other men’s sins: keep thyself pure."},"BSB":{"text":"Do not be too quick in the laying on of hands and thereby share in the sins of others. Keep yourself pure."}},"definableWords":["keep"],"peopleInVerse":[]},"23":{"text":"Drink no longer water, but use a little wine for thy stomach’s sake and thine often infirmities.","ref":"1 Timothy 5:23","synthesized":"Stop drinking only water and use a little wine instead, because of your stomach and your frequent ailments.","sources":{"KJV":{"text":"Drink no longer water, but use a little wine for thy stomach’s sake and thine often infirmities."},"BSB":{"text":"Stop drinking only water and use a little wine instead, because of your stomach and your frequent ailments."}},"definableWords":["water"],"peopleInVerse":[]},"24":{"text":"Some men’s sins are open beforehand, going before to judgment; and some men they follow after.","ref":"1 Timothy 5:24","synthesized":"The sins of some men are obvious, going ahead of them to judgment; but the sins of others do not surface until later.","sources":{"KJV":{"text":"Some men’s sins are open beforehand, going before to judgment; and some men they follow after."},"BSB":{"text":"The sins of some men are obvious, going ahead of them to judgment; but the sins of others do not surface until later."}},"definableWords":["men","judgment"],"peopleInVerse":[]},"25":{"text":"Likewise also the good works of some are manifest beforehand; and they that are otherwise cannot be hid.","ref":"1 Timothy 5:25","synthesized":"In the same way, good deeds are obvious, and even the ones that are inconspicuous cannot remain hidden.","sources":{"KJV":{"text":"Likewise also the good works of some are manifest beforehand; and they that are otherwise cannot be hid."},"BSB":{"text":"In the same way, good deeds are obvious, and even the ones that are inconspicuous cannot remain hidden."}},"definableWords":["way","good"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"FIGHT THE GOOD FIGHT","verses":{"1":{"text":"Let as many servants as are under the yoke count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed.","ref":"1 Timothy 6:1","synthesized":"All who are under the yoke of slavery should regard their masters as fully worthy of honor, so that God’s name and our teaching will not be discredited.","sources":{"KJV":{"text":"Let as many servants as are under the yoke count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed."},"BSB":{"text":"All who are under the yoke of slavery should regard their masters as fully worthy of honor, so that God’s name and our teaching will not be discredited."}},"definableWords":["God","name"],"peopleInVerse":[]},"2":{"text":"And they that have believing masters, let them not despise them, because they are brethren; but rather do them service, because they are faithful and beloved, partakers of the benefit. These things teach and exhort.","ref":"1 Timothy 6:2","synthesized":"Those who have believing masters should not show disrespect because they are brothers, but should serve them all the more, since those receiving their good service are beloved believers. Teach and encourage these principles.","sources":{"KJV":{"text":"And they that have believing masters, let them not despise them, because they are brethren; but rather do them service, because they are faithful and beloved, partakers of the benefit. These things teach and exhort."},"BSB":{"text":"Those who have believing masters should not show disrespect because they are brothers, but should serve them all the more, since those receiving their good service are beloved believers. Teach and encourage these principles."}},"definableWords":["good"],"peopleInVerse":[]},"3":{"text":"If any man teach otherwise, and consent not to wholesome words, even the words of our Lord Jesus Christ, and to the doctrine which is according to godliness;","ref":"1 Timothy 6:3","synthesized":"If anyone teaches another doctrine and disagrees with the sound words of our Lord Jesus Christ and with godly teaching,","sources":{"KJV":{"text":"If any man teach otherwise, and consent not to wholesome words, even the words of our Lord Jesus Christ, and to the doctrine which is according to godliness;"},"BSB":{"text":"If anyone teaches another doctrine and disagrees with the sound words of our Lord Jesus Christ and with godly teaching,"}},"definableWords":["Lord","Christ"],"peopleInVerse":["Jesus"]},"4":{"text":"He is proud, knowing nothing, but doting about questions and strifes of words, whereof cometh envy, strife, railings, evil surmisings,","ref":"1 Timothy 6:4","synthesized":"he is conceited and understands nothing. Instead, he has an unhealthy interest in controversies and semantics, out of which come envy, strife, abusive talk, evil suspicions,","sources":{"KJV":{"text":"He is proud, knowing nothing, but doting about questions and strifes of words, whereof cometh envy, strife, railings, evil surmisings,"},"BSB":{"text":"he is conceited and understands nothing. Instead, he has an unhealthy interest in controversies and semantics, out of which come envy, strife, abusive talk, evil suspicions,"}},"definableWords":["evil"],"peopleInVerse":[]},"5":{"text":"Perverse disputings of men of corrupt minds, and destitute of the truth, supposing that gain is godliness: from such withdraw thyself.","ref":"1 Timothy 6:5","synthesized":"and constant friction between men of depraved mind who are devoid of the truth. These men regard godliness as a means of gain.","sources":{"KJV":{"text":"Perverse disputings of men of corrupt minds, and destitute of the truth, supposing that gain is godliness: from such withdraw thyself."},"BSB":{"text":"and constant friction between men of depraved mind who are devoid of the truth. These men regard godliness as a means of gain."}},"definableWords":["men","mind","truth"],"peopleInVerse":[]},"6":{"text":"But godliness with contentment is great gain.","ref":"1 Timothy 6:6","synthesized":"Of course, godliness with contentment is great gain.","sources":{"KJV":{"text":"But godliness with contentment is great gain."},"BSB":{"text":"Of course, godliness with contentment is great gain."}},"definableWords":["great"],"peopleInVerse":[]},"7":{"text":"For we brought nothing into this world, and it is certain we can carry nothing out.","ref":"1 Timothy 6:7","synthesized":"For we brought nothing into the world, so we cannot carry anything out of it.","sources":{"KJV":{"text":"For we brought nothing into this world, and it is certain we can carry nothing out."},"BSB":{"text":"For we brought nothing into the world, so we cannot carry anything out of it."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And having food and raiment let us be therewith content.","ref":"1 Timothy 6:8","synthesized":"But if we have food and clothing, we will be content with these.","sources":{"KJV":{"text":"And having food and raiment let us be therewith content."},"BSB":{"text":"But if we have food and clothing, we will be content with these."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"But they that will be rich fall into temptation and a snare, and into many foolish and hurtful lusts, which drown men in destruction and perdition.","ref":"1 Timothy 6:9","synthesized":"Those who want to be rich, however, fall into temptation and become ensnared by many foolish and harmful desires that plunge them into ruin and destruction.","sources":{"KJV":{"text":"But they that will be rich fall into temptation and a snare, and into many foolish and hurtful lusts, which drown men in destruction and perdition."},"BSB":{"text":"Those who want to be rich, however, fall into temptation and become ensnared by many foolish and harmful desires that plunge them into ruin and destruction."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For the love of money is the root of all evil: which while some coveted after, they have erred from the faith, and pierced themselves through with many sorrows.","ref":"1 Timothy 6:10","synthesized":"For the love of money is the root of all kinds of evil. By craving it, some have wandered away from the faith and pierced themselves with many sorrows.","sources":{"KJV":{"text":"For the love of money is the root of all evil: which while some coveted after, they have erred from the faith, and pierced themselves through with many sorrows."},"BSB":{"text":"For the love of money is the root of all kinds of evil. By craving it, some have wandered away from the faith and pierced themselves with many sorrows."}},"definableWords":["love","evil","faith"],"peopleInVerse":[]},"11":{"text":"But thou, O man of God, flee these things; and follow after righteousness, godliness, faith, love, patience, meekness.","ref":"1 Timothy 6:11","synthesized":"But you, O man of God, flee from these things and pursue righteousness, godliness, faith, love, perseverance, and gentleness.","sources":{"KJV":{"text":"But thou, O man of God, flee these things; and follow after righteousness, godliness, faith, love, patience, meekness."},"BSB":{"text":"But you, O man of God, flee from these things and pursue righteousness, godliness, faith, love, perseverance, and gentleness."}},"definableWords":["man","God","righteousness","faith","love"],"peopleInVerse":[]},"12":{"text":"Fight the good fight of faith, lay hold on eternal life, whereunto thou art also called, and hast professed a good profession before many witnesses.","ref":"1 Timothy 6:12","synthesized":"Fight the good fight of the faith. Take hold of the eternal life to which you were called when you made the good confession before many witnesses.","sources":{"KJV":{"text":"Fight the good fight of faith, lay hold on eternal life, whereunto thou art also called, and hast professed a good profession before many witnesses."},"BSB":{"text":"Fight the good fight of the faith. Take hold of the eternal life to which you were called when you made the good confession before many witnesses."}},"definableWords":["fight","good","faith","eternal","life","made"],"peopleInVerse":[]},"13":{"text":"I give thee charge in the sight of God, who quickeneth all things, and before Christ Jesus, who before Pontius Pilate witnessed a good confession;","ref":"1 Timothy 6:13","synthesized":"I charge you in the presence of God, who gives life to all things, and of Christ Jesus, who made the good confession in His testimony before Pontius Pilate:","sources":{"KJV":{"text":"I give thee charge in the sight of God, who quickeneth all things, and before Christ Jesus, who before Pontius Pilate witnessed a good confession;"},"BSB":{"text":"I charge you in the presence of God, who gives life to all things, and of Christ Jesus, who made the good confession in His testimony before Pontius Pilate:"}},"definableWords":["charge","God","life","Christ","made","good"],"peopleInVerse":["Jesus","Pilate"]},"14":{"text":"That thou keep this commandment without spot, unrebukeable, until the appearing of our Lord Jesus Christ:","ref":"1 Timothy 6:14","synthesized":"Keep this commandment without stain or reproach until the appearance of our Lord Jesus Christ,","sources":{"KJV":{"text":"That thou keep this commandment without spot, unrebukeable, until the appearing of our Lord Jesus Christ:"},"BSB":{"text":"Keep this commandment without stain or reproach until the appearance of our Lord Jesus Christ,"}},"definableWords":["keep","commandment","or","Lord","Christ"],"peopleInVerse":["Jesus"]},"15":{"text":"Which in his times he shall shew, who is the blessed and only Potentate, the King of kings, and Lord of lords;","ref":"1 Timothy 6:15","synthesized":"which the blessed and only Sovereign One—the King of kings and Lord of lords—will bring about in His own time.","sources":{"KJV":{"text":"Which in his times he shall shew, who is the blessed and only Potentate, the King of kings, and Lord of lords;"},"BSB":{"text":"which the blessed and only Sovereign One—the King of kings and Lord of lords—will bring about in His own time."}},"definableWords":["blessed","one","King","kings","Lord"],"peopleInVerse":[]},"16":{"text":"Who only hath immortality, dwelling in the light which no man can approach unto; whom no man hath seen, nor can see: to whom be honour and power everlasting. Amen.","ref":"1 Timothy 6:16","synthesized":"He alone is immortal and dwells in unapproachable light. No one has ever seen Him, nor can anyone see Him. To Him be honor and eternal dominion! Amen.","sources":{"KJV":{"text":"Who only hath immortality, dwelling in the light which no man can approach unto; whom no man hath seen, nor can see: to whom be honour and power everlasting. Amen."},"BSB":{"text":"He alone is immortal and dwells in unapproachable light. No one has ever seen Him, nor can anyone see Him. To Him be honor and eternal dominion! Amen."}},"definableWords":["light","one","see","eternal","dominion"],"peopleInVerse":[]},"17":{"text":"Charge them that are rich in this world, that they be not highminded, nor trust in uncertain riches, but in the living God, who giveth us richly all things to enjoy;","ref":"1 Timothy 6:17","synthesized":"Instruct those who are rich in the present age not to be conceited and not to put their hope in the uncertainty of wealth, but in God, who richly provides all things for us to enjoy.","sources":{"KJV":{"text":"Charge them that are rich in this world, that they be not highminded, nor trust in uncertain riches, but in the living God, who giveth us richly all things to enjoy;"},"BSB":{"text":"Instruct those who are rich in the present age not to be conceited and not to put their hope in the uncertainty of wealth, but in God, who richly provides all things for us to enjoy."}},"definableWords":["hope","God"],"peopleInVerse":[]},"18":{"text":"That they do good, that they be rich in good works, ready to distribute, willing to communicate;","ref":"1 Timothy 6:18","synthesized":"Instruct them to do good, to be rich in good works, and to be generous and ready to share,","sources":{"KJV":{"text":"That they do good, that they be rich in good works, ready to distribute, willing to communicate;"},"BSB":{"text":"Instruct them to do good, to be rich in good works, and to be generous and ready to share,"}},"definableWords":["good","works"],"peopleInVerse":[]},"19":{"text":"Laying up in store for themselves a good foundation against the time to come, that they may lay hold on eternal life.","ref":"1 Timothy 6:19","synthesized":"treasuring up for themselves a firm foundation for the future, so that they may take hold of that which is truly life.","sources":{"KJV":{"text":"Laying up in store for themselves a good foundation against the time to come, that they may lay hold on eternal life."},"BSB":{"text":"treasuring up for themselves a firm foundation for the future, so that they may take hold of that which is truly life."}},"definableWords":["life"],"peopleInVerse":[]},"20":{"text":"O Timothy, keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called:","ref":"1 Timothy 6:20","synthesized":"O Timothy, guard what has been entrusted to you. Avoid irreverent, empty chatter and the opposing arguments of so-called “knowledge,”","sources":{"KJV":{"text":"O Timothy, keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called:"},"BSB":{"text":"O Timothy, guard what has been entrusted to you. Avoid irreverent, empty chatter and the opposing arguments of so-called “knowledge,”"}},"definableWords":["knowledge"],"peopleInVerse":[]},"21":{"text":"Which some professing have erred concerning the faith. Grace be with thee. Amen.","ref":"1 Timothy 6:21","synthesized":"which some have professed and thus swerved away from the faith.  Grace be with you all.","sources":{"KJV":{"text":"Which some professing have erred concerning the faith. Grace be with thee. Amen."},"BSB":{"text":"which some have professed and thus swerved away from the faith.  Grace be with you all."}},"definableWords":["faith","grace"],"peopleInVerse":[]}}}};